def format_rag_context(retrieved_docs: list, query: str) -> str:
    context = "\n".join([
        f"[DOC-{i+1}] {doc['content']} (relevance: {doc['score']:.2f})"
        for i, doc in enumerate(retrieved_docs)
    ])
    prompt = f"""Answer the query using ONLY the provided context:

Context:
{context}

Query: {query}

Answer with citations like [DOC-1]:
"""
    return prompt

rag_agent.add_prompt_template(format_rag_context)

import re

def extract_citations(response: str) -> list:
    citations = re.findall(r'\[DOC-(\d+)\]', response)
    return list(set(citations))

def validate_citations(response: str, retrieved_docs: list) -> dict:
    cited_docs = extract_citations(response)
    valid_citations = [doc for i, doc in enumerate(retrieved_docs) 
                      if str(i+1) in cited_docs]
    return {
        'total_cited': len(cited_docs),
        'valid_citations': len(valid_citations),
        'coverage': len(valid_citations) / len(cited_docs) if cited_docs else 1.0
    }

