from vex_sdk import Vex
from beeai import AgentEvent

vex = Vex(api_key="your-vex-key")

@vex.listener("beeai")
def rag_verification(events: list[AgentEvent]):
    for event in events:
        if event.type == "tool_call" and event.tool_name == "retrieve_docs":
            # Verify retrieval relevance
            docs = event.tool_output
            vex.verify_retrieval(
                query=event.input,
                documents=docs,
                threshold=0.7  # Min relevance score
            )
        elif event.type == "agent_response":
            vex.verify_rag_output(
                response=event.output,
                sources=event.context,
                checks=["faithfulness", "citation_accuracy"]
            )

@vex.guardrail("memory_safety")
def check_rag_memory(event: AgentEvent):
    if event.type == "memory_update":
        memory_size = len(event.memory_state)
        if memory_size > 10000:  # Token limit
            return {
                'block': True,
                'reason': 'Memory exceeds RAG safety limit',
                'action': 'prune_context'
            }
    return {'pass': True}

# Register with BeeAI agent
rag_agent.add_event_listener(check_rag_memory)

@vex.guardrail("rag_fidelity")
def verify_rag_fidelity(event: AgentEvent):
    if event.type == "final_response":
        response = event.output
        context_docs = event.context

        results = vex.evaluate({
            'response': response,
            'context': [doc['content'] for doc in context_docs],
            'metrics': ['faithfulness', 'answer_relevancy', 'context_precision']
        })

        if results['faithfulness'] < 0.8:
            return {
                'block': True,
                'reason': f'Low faithfulness score: {results["faithfulness"]}',
                'evidence': results['failed_spans']
            }
    return {'pass': True}
